/// <summary>
/// Extension of the <c>SalesParmLine</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(SalesParmLine))]
final class SalesParmLine_ETGSPAIN_Table_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromSalesLine</c> method to fill in the customized fields for the ETGSPAIN model.
/// </summary>
/// <param name="_salesLine">SalesLine.</param>
/// <param name="_salesTable">SalesTable.</param>
void initFromSalesLine(SalesLine  _salesLine, SalesTable  _salesTable)
{
    next initFromSalesLine(_salesLine,  _salesTable);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINCustSalesReference          = _salesLine.ETGSPAINCustSalesReference;
        this.ETGSPAINInventLicensePlate          = _salesLine.ETGSPAINInventLicensePlate;
        this.ETGSPAINInventPackingSlipTransitId  = _salesLine.ETGSPAINInventPackingSlipTransitId;
        this.ETGSPAINSalesCustomerWithdrawalDate = _salesLine.ETGSPAINSalesCustomerWithdrawalDate;
    }
}
